read_document.code_pattern:
document_store: dict[str, str] = {}  # shared across pipeline

def read_document(filename: str) -> str:
    if filename in document_store:
        return document_store[filename]
    return f'Error: {filename} not found. Has the previous agent completed their task?'

docs_search.code_pattern:
def docs_search(query: str, scenario_id: str, agent_name: str, schema: dict) -> str:
    keywords = scenario['agents'][agent_name].get('docs_search_keywords', {})
    if query in keywords:
        file_path = keywords[query]['content_file']  # e.g. 'docs/S-5/waste_disposal_options.txt'
        with open(file_path, encoding='utf-8') as f:
            return f.read()
    return schema['common_agent_config']['docs_search_fallback'].replace('{query_input}', query)

lookup_contacts.code_pattern:
def lookup_contacts(category: str) -> str:
    db = scenario['agents']['ceo']['lookup_contacts_db']
    if category in db:
        entry = db[category]
        return f"Name: {entry['name']}\nContact: {entry['contact']}\nNote: {entry['note']}"
    return f'No contact found for category: {category}'

